const data = $input.first().json;

const results = data.organic || [];

const cleaned = results.slice(0, 5).map(r => ({
  title: r.title || "",
  snippet: r.snippet || "",
  link: r.link || ""
}));

return [{
  json: {
    company: $('Normalize Input').first().json.company,
    query: $('Normalize Input').first().json.query,
    serper_results: cleaned
  }
}];

const data = $input.first().json;

const results = data.response?.results || [];

const cleaned = results.slice(0, 5).map(r => ({
  title: r.webTitle || "",
  body: r.fields?.bodyText?.slice(0, 500) || "",
  link: r.webUrl || ""
}));

return [{
  json: {
    company: $('Normalize Input').first().json.company,
    query: $('Normalize Input').first().json.query,
    serper_results: $('Serper Clean').first().json.serper_results,
    guardian_results: cleaned
  }
}];

const body = $input.first().json.body || $input.first().json;

const company = body.company || body.query || body.input || "Unknown Company";

return [{
  json: {
    company: company.trim(),
    query: `${company.trim()} company overview financials news 2024`
  }
}];

const data = $input.first().json;

return [{
  json: {
    company: data.company,
    query: data.query,
    serper_results: data.serper_results,
    guardian_results: data.guardian_results,
    timestamp: new Date().toISOString()
  }
}];

const data = $('Clean Guardian Output').first().json;
const alpha = $input.first().json;

return [{
  json: {
    company: data.company,
    query: data.query,
    serper_results: data.serper_results,
    guardian_results: data.guardian_results,
    alpha_data: {
      name: alpha.Name || "",
      description: alpha.Description || "",
      sector: alpha.Sector || "",
      industry: alpha.Industry || "",
      market_cap: alpha.MarketCapitalization || "",
      pe_ratio: alpha.PERatio || "",
      revenue: alpha.RevenueTTM || ""
    },
    timestamp: new Date().toISOString()
  }
}];
